package main

import (
    "crypto/aes"
    "crypto/cipher"
    "crypto/rand"
    "crypto/sha256"
    "golang.org/x/crypto/argon2"
    "golang.org/x/crypto/chacha20poly1305"
    "errors"
)

// Compliant: Using AES-256 with GCM mode
func encryptAES256GCM(data, password []byte) ([]byte, error) {
    // Derive a strong 256-bit key using Argon2
    salt := make([]byte, 16)
    if _, err := rand.Read(salt); err != nil {
        return nil, err
    }

    key := argon2.IDKey(password, salt, 1, 64*1024, 4, 32) // 256-bit key

    block, err := aes.NewCipher(key)
    if err != nil {
        return nil, err
    }

    // Use GCM mode for authenticated encryption
    gcm, err := cipher.NewGCM(block)
    if err != nil {
        return nil, err
    }

    // Generate random nonce
    nonce := make([]byte, gcm.NonceSize())
    if _, err := rand.Read(nonce); err != nil {
        return nil, err
    }

    // Encrypt and authenticate
    ciphertext := gcm.Seal(nil, nonce, data, nil)

    // Prepend salt and nonce to ciphertext
    result := append(salt, nonce...)
    result = append(result, ciphertext...)

    return result, nil
}

func decryptAES256GCM(encryptedData, password []byte) ([]byte, error) {
    if len(encryptedData) < 28 { // salt(16) + nonce(12) minimum
        return nil, errors.New("encrypted data too short")
    }

    // Extract salt and nonce
    salt := encryptedData[:16]
    nonce := encryptedData[16:28]
    ciphertext := encryptedData[28:]

    // Derive key using the same parameters
    key := argon2.IDKey(password, salt, 1, 64*1024, 4, 32)

    block, err := aes.NewCipher(key)
    if err != nil {
        return nil, err
    }

    gcm, err := cipher.NewGCM(block)
    if err != nil {
        return nil, err
    }

    // Decrypt and verify authentication
    plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
    if err != nil {
        return nil, err
    }

    return plaintext, nil
}

// Compliant: Using ChaCha20-Poly1305 (modern AEAD cipher)
func encryptChaCha20(data, password []byte) ([]byte, error) {
    // Derive key using SHA-256 (for simplicity; Argon2 is better)
    hash := sha256.Sum256(password)
    key := hash[:]

    aead, err := chacha20poly1305.New(key)
    if err != nil {
        return nil, err
    }

    // Generate random nonce
    nonce := make([]byte, aead.NonceSize())
    if _, err := rand.Read(nonce); err != nil {
        return nil, err
    }

    // Encrypt with authenticated encryption
    ciphertext := aead.Seal(nil, nonce, data, nil)

    // Prepend nonce
    result := append(nonce, ciphertext...)
    return result, nil
}

// Compliant: Proper key derivation function
func deriveKeySecure(password, salt []byte) []byte {
    // Use Argon2id - current best practice for password hashing
    // Parameters: time=1, memory=64MB, threads=4, keyLen=32
    return argon2.IDKey(password, salt, 1, 64*1024, 4, 32)
}

// Compliant: Secure random salt generation
func generateSalt() ([]byte, error) {
    salt := make([]byte, 16)
    _, err := rand.Read(salt)
    return salt, err
}

// Compliant: Complete encryption utility
type SecureEncryption struct {
    password []byte
}

func NewSecureEncryption(password []byte) *SecureEncryption {
    return &SecureEncryption{password: password}
}

func (se *SecureEncryption) Encrypt(data []byte) ([]byte, error) {
    return encryptAES256GCM(data, se.password)
}

func (se *SecureEncryption) Decrypt(encryptedData []byte) ([]byte, error) {
    return decryptAES256GCM(encryptedData, se.password)
